{"code": "import json

# Access the file path from the storage
db_result_key = 'var_functions.query_db:6'
business_data_path = locals()[db_result_key]

# Load the business data from the file
with open(business_data_path, 'r') as f:
    businesses = json.load(f)

print('Total businesses: ' + str(len(businesses)))

# Collect all WiFi values to understand the format
wifi_values = {}
for business in businesses:
    attributes = business.get('attributes')
    if attributes and attributes != 'None':
        wifi = attributes.get('WiFi')
        if wifi is not None:
            wifi_str = str(wifi)
            wifi_values[wifi_str] = wifi_values.get(wifi_str, 0) + 1

print('Unique WiFi values and counts:')
wifi_list = list(sorted(wifi_values.items()))
print(str(wifi_list))

# Check sample businesses with WiFi
print('\nSample businesses with WiFi:')
samples = []
for business in businesses:
    attributes = business.get('attributes')
    if attributes and attributes != 'None':
        wifi = attributes.get('WiFi')
        if wifi is not None:
            samples.append({
                'name': business['name'],
                'wifi': str(wifi)
            })
            if len(samples) >= 5:
                break

print(str(samples))

result = {
    'total_businesses': len(businesses),
    'wifi_value_counts': wifi_values,
    'wifi_samples': samples
}

print('__RESULT__:')
print(json.dumps(result))"}

{"code": "import json
import re
from collections import defaultdict

# Get the data from storage
top_state_result = var_functions.query_db:34

# Process to find top state
wifi_by_state = defaultdict(list)

for business in top_state_result:
    desc = business.get('description', '')
    if not desc:
        continue

    match = re.search(r',\s*([A-Z]{2})\b', desc)
    if match:
        state = match.group(1)
        wifi_by_state[state].append(business['business_id'])

state_counts = {state: len(ids) for state, ids in wifi_by_state.items()}
if state_counts:
    top_state = max(state_counts.items(), key=lambda x: x[1])
else:
    top_state = (None, 0)

print('State counts:', json.dumps(state_counts))
print('Top state:', top_state[0], 'with', top_state[1], 'businesses')

result = {
    'top_state': top_state[0],
    'top_state_count': top_state[1],
    'top_state_business_ids': wifi_by_state.get(top_state[0], [])
}

print('__RESULT__:')
print(json.dumps(result))"}
